from flask import Flask, request, jsonify
import secrets

app = Flask(__name__)

mfa_enabled_users = {}

def send_reset_link(email):
    reset_token = secrets.token_urlsafe(32)
    # Code to send reset link to the email goes here
    return reset_token

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    data = request.get_json()
    email = data['email']
    mfa_enabled_users[email] = True
    return jsonify({'message': 'MFA enabled successfully'})

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    data = request.get_json()
    email = data['email']
    if email in mfa_enabled_users:
        del mfa_enabled_users[email]
        return jsonify({'message': 'MFA disabled successfully'})
    return jsonify({'message': 'MFA is not enabled for the user'})

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
